arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?part ?v ?u ?partLabel ?partType ?partTypeLabel WHERE {
  <https://www.purl.org/futuram/example#V0301030104_2020> futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
      futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit ?u ] .
  ?part a ?partType .
  OPTIONAL { ?part rdfs:label ?partLabel }
  OPTIONAL { ?partType rdfs:label ?partTypeLabel }
}

