PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT DISTINCT ?part ?partLabel ?v ?u ?leafType ?leafTypeLabel WHERE {
  BIND(<https://www.purl.org/futuram/example#V0301030104_2020> AS ?whole)
  ?whole futuram:hasCompositionStatement ?stmt .
  ?stmt futuram:hasPartRelation ?pr .
  ?pr futuram:refersTo ?part ;
      futuram:hasQuantity/futuram:hasBestValue [ qudt:numericValue ?v ; qudt:unit ?u ] .
  ?part rdf:type ?leafType .
  FILTER NOT EXISTS { ?leafType rdfs:subClassOf+ <https://www.purl.org/futuram#Component> }
  OPTIONAL { ?leafType rdfs:label ?leafTypeLabel }
  OPTIONAL { ?part rdfs:label ?partLabel }
} ORDER BY ?part

