arguments.sparql_query:
PREFIX futuram: <https://www.purl.org/futuram#>
PREFIX qudt: <http://qudt.org/schema/qudt/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX crit: <http://purl.org/futuram/criticality#>
SELECT DISTINCT ?elem ?elemLabel ?chebi ?flag WHERE {
  ?elem rdfs:subClassOf ?chebi . FILTER(CONTAINS(STR(?chebi), "CHEBI"))
  ?chebi crit:remark ?flag .
  OPTIONAL { ?elem rdfs:label ?elemLabel }
} LIMIT 50

